class Queue {
    constructor(maxSize = 101) {
        this.maxSize = maxSize;
        this.a = new Array(maxSize);
        this.front = 0; // Index of the front element
        this.rear = -1; // Index of the rear element
        this.currentSize = 0;
    }

    isEmpty() {
        return this.currentSize === 0;
    }

    isFull() {
        return this.currentSize === this.maxSize;
    }

    size() {
        return this.currentSize;
    }

    enqueue(item) {
        if (this.isFull()) {
            console.log("Queue is full. Cannot enqueue.");
            return;
        }
        this.rear = (this.rear + 1) % this.maxSize;  
        this.a[this.rear] = item;
        this.currentSize++;
    }

    dequeue() {
        if (this.isEmpty()) {
            console.log("Queue is empty. Cannot dequeue.");
            return -1; 
        }
        const removedItem = this.a[this.front];
        this.front = (this.front + 1) % this.maxSize; 
        this.currentSize--;
        return removedItem;
    }
}

function main() {
    const queue = new Queue();
    const n = 10;

    for (let i = 1; i <= n; i++) {
        if (i % 2 !== 0) {
            console.log(i + " ");
        } else {
            queue.enqueue(i);
        }
